const rawText = $input.first().json.messages[0].text.body;
const lines = rawText.split('\n');
const title = lines[0].trim();
const menuLines = lines.slice(1).filter(l => l.trim() !== '');

const items = [];
let note = '';

for (const line of menuLines) {
  const colonIdx = line.indexOf(':');
  if (colonIdx > 0 && colonIdx < 4) {
    const day = line.substring(0, colonIdx).trim();
    const rest = line.substring(colonIdx + 1).trim();
    const priceMatch = rest.match(/[–\-]\s*([\d]+[,.]\d{2}\s*€?)\s*$/);
    if (priceMatch) {
      const dish = rest.substring(0, rest.lastIndexOf(priceMatch[0])).trim();
      let price = priceMatch[1].trim();
      if (!price.includes('€')) price += ' €';
      items.push({ day, dish, price });
    } else {
      items.push({ day, dish: rest, price: '' });
    }
  } else {
    note = line.trim();
  }
}

const json = {
  title,
  updated: new Date().toISOString(),
  items,
  note
};

// JSON als String für FTP-Upload
const jsonString = JSON.stringify(json, null, 2);

// Binary-Output erstellen für FTP
const buffer = Buffer.from(jsonString, 'utf-8');

return {
  json: { title, jsonString },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'application/json',
      fileName: 'wochenkarte.json'
    }
  }
};
